import React, { useState } from 'react';

interface SearchBarProps {
  onSearch: (query: string, location?: string) => void;
}

const SearchBar: React.FC<SearchBarProps> = ({ onSearch }) => {
  const [query, setQuery] = useState('');
  const [location, setLocation] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSearch(query, location);
  };

  return (
    <form onSubmit={handleSubmit} className="flex flex-col md:flex-row gap-4 max-w-2xl mx-auto mb-8">
      <input
        type="text"
        placeholder="Search for events..."
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-uncc-green focus:border-transparent"
        required
      />
      <input
        type="text"
        placeholder="Location (optional)"
        value={location}
        onChange={(e) => setLocation(e.target.value)}
        className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-uncc-green focus:border-transparent"
      />
      <button
        type="submit"
        className="px-6 py-2 bg-uncc-green text-white rounded-lg hover:bg-green-700 transition-colors"
      >
        Search
      </button>
    </form>
  );
};

export default SearchBar;
